            return current
        current += 1
        # Optimization to skip numbers that can't be special (e.g., digits > 3)
        s = str(current)
        if any(int(d) > 3 for d in s):
            # Find the first digit > 3, increment the number to skip invalid ranges
            for i, d in enumerate(s):
                if int(d) > 3:
                    # Increment the higher digit to skip invalid digits
                    new_num = int(s[:i] + '0' * (len(s) - i)) + 10 ** (len(s) - i)
                    current = new_num
                    break
